import React, { useState } from 'react';
import { View, Text, TextInput, TouchableOpacity, StyleSheet, Alert, ActivityIndicator, ScrollView } from 'react-native';
import apiClient from '../../api/client';

export default function RegisterMessScreen({ navigation }: any) {
  const [form, setForm] = useState({
    name: '', address: '', latitude: '', longitude: '',
    opening_time: '', closing_time: '', price_range: '',
  });
  const [loading, setLoading] = useState(false);

  const set = (key: string) => (val: string) => setForm((f) => ({ ...f, [key]: val }));

  const handleSubmit = async () => {
    const { name, address, latitude, longitude, opening_time, closing_time } = form;
    if (!name || !address || !latitude || !longitude || !opening_time || !closing_time) {
      Alert.alert('Error', 'All fields except price range are required');
      return;
    }
    setLoading(true);
    try {
      await apiClient.post('/messes', {
        name, address,
        latitude: parseFloat(latitude),
        longitude: parseFloat(longitude),
        opening_time, closing_time,
        price_range: form.price_range || undefined,
      });
      Alert.alert('Success', 'Mess registered successfully');
      navigation.goBack();
    } catch (err: any) {
      Alert.alert('Error', err.response?.data?.message ?? 'Failed to register mess');
    } finally {
      setLoading(false);
    }
  };

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>Register Mess</Text>
      {[
        { key: 'name', placeholder: 'Mess Name' },
        { key: 'address', placeholder: 'Address' },
        { key: 'latitude', placeholder: 'Latitude (e.g. 18.5204)', keyboardType: 'numeric' },
        { key: 'longitude', placeholder: 'Longitude (e.g. 73.8567)', keyboardType: 'numeric' },
        { key: 'opening_time', placeholder: 'Opening Time (HH:MM)' },
        { key: 'closing_time', placeholder: 'Closing Time (HH:MM)' },
        { key: 'price_range', placeholder: 'Price Range (e.g. ₹50–₹100) — optional' },
      ].map(({ key, placeholder, keyboardType }: any) => (
        <TextInput key={key} style={styles.input} placeholder={placeholder}
          value={(form as any)[key]} onChangeText={set(key)} keyboardType={keyboardType} />
      ))}
      <TouchableOpacity style={styles.btn} onPress={handleSubmit} disabled={loading}>
        {loading ? <ActivityIndicator color="#fff" /> : <Text style={styles.btnText}>Register</Text>}
      </TouchableOpacity>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { padding: 24, backgroundColor: '#fff', flexGrow: 1 },
  title: { fontSize: 22, fontWeight: 'bold', marginBottom: 20 },
  input: { borderWidth: 1, borderColor: '#ddd', borderRadius: 8, padding: 12, marginBottom: 12, fontSize: 15 },
  btn: { backgroundColor: '#f97316', padding: 14, borderRadius: 8, alignItems: 'center', marginTop: 8 },
  btnText: { color: '#fff', fontSize: 16, fontWeight: '600' },
});
